const key = (c: Cell): string => `${c[0]},${c[1]}`;

const neighborsOf = (cell: Cell): Cell[] => {
  const result: Cell[] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      result.push([cell[0] + dx, cell[1] + dy]);
    }
  }
  return result;
};

export function nextGeneration(cells: readonly Cell[]): Cell[] {
  const alive = new Set(cells.map(key));
  const survivors = cells.filter((cell) => survives(countLiveNeighbors(cell, cells)));
  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    for (const n of neighborsOf(cell)) {
      if (!alive.has(key(n))) candidates.set(key(n), n);
    }
  }
  const births: Cell[] = [];
  for (const cell of candidates.values()) {
    if (countLiveNeighbors(cell, cells) === 3) births.push(cell);
  }
  return [...survivors, ...births];
}

